// ─── 효과음 ───
const SFX = {
  hit: new Audio("audio/hit_3.mp3"),
  miss: Object.assign(new Audio("audio/miss_2.mp3"), {
    playbackRate: 1.5,
  }),
  boing: new Audio("audio/boing.mp3"),
  play(type) {
    const snd = this[type];
    snd.currentTime = 0;
    snd.play().catch(() => {});
  },
};

// ─── 팝 사운드 (pop_1.mp3 → base64 data URL → Tone.Player 정확 스케줄링) ───
const PopSFX = {
  inited: false,
  _buffer: null,
  _gainNode: null,

  async init() {
    if (this.inited) return;
    this.inited = true;
    const ctx = Tone.getContext().rawContext;
    this._gainNode = ctx.createGain();
    this._gainNode.gain.value = 1.0;
    this._gainNode.connect(ctx.destination);
    const dataUrl =
      "data:audio/mp3;base64,";
    const _tmpPlayer = new Tone.Player(dataUrl);
    await Tone.loaded();
    this._buffer = _tmpPlayer.buffer.get();
    _tmpPlayer.dispose();
  },

  trigger(time) {
    if (!this._buffer) return;
    const ctx = Tone.getContext().rawContext;
    const src = ctx.createBufferSource();
    src.buffer = this._buffer;
    src.connect(this._gainNode);
    src.start(time, 0.175); // pop_1.mp3 무음 구간 스킵 (조정값)
  },
};
